from typing import Dict, Any, List, Optional, Tuple

# -------------------------
# Deterministic rule sets
# -------------------------
NSAIDS = {"ibuprofen", "naproxen", "aspirin"}  # normalized english_name keys

PGX_AVOID = {
    # "dextromethorphan": [
    #   {"gene": "cyp2d6", "phenotype": "poor_metabolizer", "reason": "Altered exposure"},
    # ]
}

GI_BLEED_KEYS = {
    "gi_bleed", "bleeding", "hematemesis", "melena", "bloody_stool", "coffee_ground_emesis"
}

def _norm(s: str) -> str:
    return (s or "").strip().lower()

def _pill_key(pill: Dict[str, Any]) -> str:
    return _norm(pill.get("english_name") or pill.get("name") or "")

def _rx_status_raw(pill: Dict[str, Any]) -> str:
    return _norm(pill.get("otc_or_rx") or "")

def _is_otc(pill: Dict[str, Any]) -> bool:
    """
    Deterministic parsing for your dataset variants:
    - "OTC" -> True
    - "Rx" -> False
    - "OTC/Rx (varies...)" -> treat as OTC? (policy choice)
    - "OTC in many regions" -> True
    """
    raw = _rx_status_raw(pill)
    if raw == "rx":
        return False
    if "otc" in raw:
        # Policy choice:
        # If you want strict: only allow if raw startswith 'otc' and not contains 'rx'
        # return raw == "otc"
        return True
    return False

