# medical_pills.py
import os, json

def load_pill_db(path: str = "medical_knowledge/pills/pills.json"):
    global PILL_DB

    # already loaded or embedded
    if isinstance(PILL_DB, list) and len(PILL_DB) > 0:
        return PILL_DB

    if os.path.exists(path):
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
        if isinstance(data, dict) and "pills" in data:
            data = data["pills"]
        if isinstance(data, list):
            PILL_DB = data
            return PILL_DB

    # fallback: embedded dataset
    if not isinstance(PILL_DB, list):
        PILL_DB = []
    return PILL_DB



def _score_pill(
    pill: Dict[str, Any],
    user_text: str,
    symptoms: Optional[list],
    diseases: Optional[list]
) -> float:
    score = 0.0
    text_norm = _norm(user_text)

    if symptoms:
        pill_syms = set(_norm(s) for s in (pill.get("for_symptoms", []) or []))
        overlap = pill_syms.intersection(set(_norm(s) for s in symptoms))
        score += len(overlap) * 2.0

    if diseases:
        pill_dis = set(_norm(d) for d in (pill.get("for_diseases", []) or []))
        overlap_d = pill_dis.intersection(set(_norm(d) for d in diseases))
        score += len(overlap_d) * 1.5

    # expanded keyword check
    keyword_fields: List[str] = []
    keyword_fields.extend(pill.get("for_symptoms", []) or [])
    keyword_fields.extend(pill.get("indications", []) or [])
    keyword_fields.append(pill.get("name", "") or "")
    keyword_fields.append(pill.get("english_name", "") or "")
    keyword_fields.append(pill.get("drug_class", "") or "")

    for kw in keyword_fields:
        kw_n = _norm(kw)
        if kw_n and kw_n in text_norm:
            score += 1.0

    return score

def policy_gate(
    pill: Dict[str, Any],
    context: Dict[str, Any],
    triage: Dict[str, Any],
    scope: str,
) -> Tuple[bool, List[str]]:
    """
    Deterministic hard gate: returns (allowed, block_reasons).
    """
    key = _pill_key(pill)

    # 1) scope gate
    if scope in ("er_now", "needs_clinician"):
        return False, [f"scope_block:{scope}"]

    # 2) OTC/RX boundary
    if not _is_otc(pill):
        return False, ["rx_boundary_block"]

    # 3) red-flag blocks (NSAIDs + GI bleed)
    red_flags = set(_norm(x) for x in (triage.get("red_flags", []) or []))
    if key in NSAIDS and (red_flags.intersection(GI_BLEED_KEYS)):
        return False, ["red_flag_block:nsaid_gi_bleed"]

    # 4) NSAIDs CV risk block
    high_cv_risk = bool(context.get("heart_risk", False))
    if not high_cv_risk:
        comorbid = set(_norm(x) for x in (context.get("comorbidities", []) or []))
        high_cv_risk = ("high_cv_risk" in comorbid) or ("heart_disease" in comorbid)

    if key in NSAIDS and high_cv_risk:
        return False, ["cv_risk_block:nsaids"]

    # 5) PGx blocks
    pgx = context.get("pgx", {}) or {}
    for rule in (PGX_AVOID.get(key) or []):
        gene = _norm(rule.get("gene"))
        phenotype = _norm(rule.get("phenotype"))
        if gene and phenotype and _norm(pgx.get(gene, "")) == phenotype:
            return False, [f"pgx_block:{gene}:{phenotype}:{rule.get('reason','')}"]

    return True, []

def build_mechanism_card(pill: Dict[str, Any]) -> Dict[str, Any]:
    return {
        "name": pill.get("name", ""),
        "english_name": pill.get("english_name", ""),
        "rx_status": pill.get("otc_or_rx", ""),
        "drug_class": pill.get("drug_class", ""),
        "description": pill.get("description", ""),
        "indications": pill.get("indications", []) or [],
        "for_symptoms": pill.get("for_symptoms", []) or [],
        "for_diseases": pill.get("for_diseases", []) or [],
        "contraindication_notes": pill.get("contraindication_notes", []) or [],
        "common_side_effects": pill.get("common_side_effects", []) or [],
        "brand_example": pill.get("brand_example", "") or "",
    }

def pill_recommendation(
    user_text: str,
    user_symptoms: Optional[list] = None,
    top_diseases: Optional[list] = None,
    top_k: int = 3,
    context: Optional[Dict[str, Any]] = None,
    triage: Optional[Dict[str, Any]] = None,
    scope: str = "limited_otc",
    include_blocked: bool = True,
) -> Dict[str, Any]:
    """
    Deterministic: score -> policy gate -> rank -> return explanation payload.
    """
    context = context or {}
    triage = triage or {}

    disease_names: List[str] = []
    if top_diseases:
        for d in top_diseases:
            name = (d.get("disease") or d.get("disease_name") or d.get("name")) if isinstance(d, dict) else d
            if name:
                disease_names.append(name)

    scored: List[Tuple[float, Dict[str, Any]]] = []
    for pill in PILL_DB:
        s = _score_pill(pill, user_text, user_symptoms, disease_names)
        if s > 0:
            scored.append((s, pill))

    if not scored:
        return {"scope": scope, "recommended": [], "blocked": [], "note": "no_match"}

    scored.sort(reverse=True, key=lambda x: x[0])

    recommended: List[Dict[str, Any]] = []
    blocked: List[Dict[str, Any]] = []

    for s, pill in scored:
        ok, reasons = policy_gate(pill, context=context, triage=triage, scope=scope)
        if ok:
            recommended.append({
                "score": float(s),
                "pill": pill,
                "card": build_mechanism_card(pill),
            })
        else:
            if include_blocked:
                blocked.append({
                    "score": float(s),
                    "pill": pill,
                    "block_reasons": reasons,
                    "card": build_mechanism_card(pill),
                })

        # IMPORTANT: do NOT break too early if most top hits are blocked
        if len(recommended) >= top_k:
            break

    return {
        "scope": scope,
        "recommended": recommended,
        "blocked": blocked,
        "principles_applied": {
            "otc_rx_boundary": True,
            "red_flag_block": True,
            "nsaids_cv_block": True,
            "pgx_block": True,
        },
        "note": "Deterministic recommendation; cards for explanation only."
    }

def summarize_pills(med_pack: Dict[str, Any]) -> str:
    rec = med_pack.get("recommended", []) or []
    if not rec:
        return ""

    parts = []
    for item in rec:
        pill = item.get("pill", {}) or {}
        name = pill.get("name", "Unknown")
        cls = pill.get("drug_class", "OTC")
        example = pill.get("brand_example", "")

        if example:
            parts.append(f"{name} ({example}, {cls})")
        else:
            parts.append(f"{name} ({cls})")

    return "Possible over-the-counter medicine options include: " + "; ".join(parts) + "."
